"""Account service — manages account records.

Includes three validators (email, phone, url) used by create_account
and update_account. These were written separately from user_service's
validators and use partition/split-based checks rather than regex.
"""


def validate_email(email):
    """Return True iff `email` looks like a valid address.
    Partition-based check (no regex).
    """
    if not isinstance(email, str) or not email:
        return False
    if email.count("@") != 1:
        return False
    local, _, domain = email.partition("@")
    if not local or not domain:
        return False
    if " " in local or " " in domain:
        return False
    if "." not in domain:
        return False
    if domain.startswith(".") or domain.endswith("."):
        return False
    return True


def validate_phone(phone):
    """Return True iff `phone` is a 7-15 digit number (optionally +-prefixed).
    Manual digit-strip implementation.
    """
    if not isinstance(phone, str) or not phone:
        return False
    candidate = phone[1:] if phone.startswith("+") else phone
    if not candidate:
        return False
    for ch in candidate:
        if not ch.isdigit():
            return False
    return 7 <= len(candidate) <= 15


def validate_url(url):
    """Return True iff `url` is an http(s) URL with a host.
    Scheme-split based check.
    """
    if not isinstance(url, str) or not url:
        return False
    if url.startswith("https://"):
        rest = url[len("https://"):]
    elif url.startswith("http://"):
        rest = url[len("http://"):]
    else:
        return False
    if not rest:
        return False
    host = rest.split("/", 1)[0]
    if not host or " " in host:
        return False
    return True


def create_account(email, account_type, phone=None):
    """Create an account dict. Raises ValueError if email/phone is invalid."""
    if not validate_email(email):
        raise ValueError(f"invalid email: {email!r}")
    if phone is not None and not validate_phone(phone):
        raise ValueError(f"invalid phone: {phone!r}")
    return {"email": email, "type": account_type, "phone": phone, "balance": 0}


def update_account_callback(account_id, url):
    """Update an account's callback URL. Raises ValueError if invalid."""
    if not validate_url(url):
        raise ValueError(f"invalid url: {url!r}")
    return {"id": account_id, "callback_url": url}


def close_account(account_id):
    """Close an account. Stub — returns success."""
    return {"id": account_id, "closed": True}

