"""Billing service — manages billing records.

Includes three validators (email, phone, url) used by
add_payment_method and set_invoice_webhook. Third independent
implementation set — uses string-method calls and explicit length
checks.
"""


def validate_email(email):
    """Return True iff `email` looks like a valid address.
    String-method based check.
    """
    if not isinstance(email, str) or len(email) == 0:
        return False
    if "@" not in email or email.count("@") != 1:
        return False
    parts = email.split("@", 1)
    if not parts[0] or not parts[1]:
        return False
    if " " in parts[0] or " " in parts[1]:
        return False
    if "." not in parts[1]:
        return False
    if parts[1].startswith(".") or parts[1].endswith("."):
        return False
    return True


def validate_phone(phone):
    """Return True iff `phone` is a 7-15 digit number (optionally +-prefixed).
    String-method based; explicit length bounds.
    """
    if not isinstance(phone, str) or len(phone) == 0:
        return False
    body = phone[1:] if phone[0] == "+" else phone
    if len(body) < 7 or len(body) > 15:
        return False
    return body.isdigit()


def validate_url(url):
    """Return True iff `url` is an http(s) URL with a host.
    Prefix-check based.
    """
    if not isinstance(url, str) or len(url) == 0:
        return False
    if url.startswith("https://"):
        host_and_path = url[8:]
    elif url.startswith("http://"):
        host_and_path = url[7:]
    else:
        return False
    if not host_and_path:
        return False
    # Find the first slash (or end-of-string) to isolate the host.
    slash_idx = host_and_path.find("/")
    host = host_and_path if slash_idx == -1 else host_and_path[:slash_idx]
    if not host or " " in host:
        return False
    return True


def add_payment_method(email, card_last4, phone=None):
    """Add a payment method. Raises ValueError if email/phone invalid."""
    if not validate_email(email):
        raise ValueError(f"invalid email: {email!r}")
    if phone is not None and not validate_phone(phone):
        raise ValueError(f"invalid phone: {phone!r}")
    return {"email": email, "card_last4": card_last4, "phone": phone, "active": True}


def set_invoice_webhook(account_id, url):
    """Set an invoice webhook URL. Raises ValueError if invalid."""
    if not validate_url(url):
        raise ValueError(f"invalid url: {url!r}")
    return {"id": account_id, "webhook_url": url}


def list_payment_methods(account_id):
    """List payment methods for an account. Stub."""
    return [{"id": 1, "card_last4": "4242"}]

