"""User service — handles user creation and lookup.

Includes three validators (email, phone, url) used by create_user and
update_user. The validators here are regex-based — the original
user-service author preferred a single source of truth via patterns.
"""
import re

# Approximate validators: regex-based, anchored, no whitespace.
_EMAIL_RE = re.compile(r"^[^@\s]+@[^@\s]+\.[^@\s]+$")
_PHONE_RE = re.compile(r"^\+?[0-9]{7,15}$")
_URL_RE = re.compile(r"^https?://[^\s/]+(/.*)?$")


def validate_email(email):
    """Return True iff `email` looks like a valid address."""
    if not isinstance(email, str) or not email:
        return False
    return bool(_EMAIL_RE.match(email))


def validate_phone(phone):
    """Return True iff `phone` is a 7-15 digit number (optionally +-prefixed)."""
    if not isinstance(phone, str) or not phone:
        return False
    return bool(_PHONE_RE.match(phone))


def validate_url(url):
    """Return True iff `url` is an http(s) URL with a host."""
    if not isinstance(url, str) or not url:
        return False
    return bool(_URL_RE.match(url))


def create_user(email, name, phone=None):
    """Create a user dict. Raises ValueError if email/phone is invalid."""
    if not validate_email(email):
        raise ValueError(f"invalid email: {email!r}")
    if phone is not None and not validate_phone(phone):
        raise ValueError(f"invalid phone: {phone!r}")
    return {"email": email, "name": name, "phone": phone, "status": "active"}


def update_user_website(user_id, url):
    """Update a user's website. Raises ValueError if url is invalid."""
    if not validate_url(url):
        raise ValueError(f"invalid url: {url!r}")
    return {"id": user_id, "website": url}


def lookup_user(user_id):
    """Look up a user by id. Stub — returns a fixed user."""
    return {"id": user_id, "email": "stub@example.com", "name": "Stub"}

