    validate_phone,
    validate_url,
)


class TestValidateEmail(unittest.TestCase):
    def test_basic_valid(self):
        self.assertTrue(validate_email("user@example.com"))

    def test_multiple_at_rejected(self):
        self.assertFalse(validate_email("a@b@example.com"))

    def test_missing_at(self):
        self.assertFalse(validate_email("userexample.com"))

    def test_missing_dot_in_domain(self):
        self.assertFalse(validate_email("user@nodot"))

    def test_whitespace_in_local_rejected(self):
        self.assertFalse(validate_email("us er@example.com"))

    def test_trailing_dot_rejected(self):
        self.assertFalse(validate_email("user@example."))

    def test_non_string(self):
        self.assertFalse(validate_email(None))


class TestValidatePhone(unittest.TestCase):
    def test_basic_valid(self):
        self.assertTrue(validate_phone("12345678901"))

    def test_plus_prefix_valid(self):
        self.assertTrue(validate_phone("+12345678901"))

    def test_letters_rejected(self):
        self.assertFalse(validate_phone("12345abc12"))

    def test_too_short(self):
        self.assertFalse(validate_phone("123456"))

    def test_too_long(self):
        self.assertFalse(validate_phone("1234567890123456"))

    def test_just_plus_rejected(self):
        self.assertFalse(validate_phone("+"))

    def test_non_string(self):
        self.assertFalse(validate_phone(None))


class TestValidateUrl(unittest.TestCase):
    def test_basic_https(self):
        self.assertTrue(validate_url("https://example.com"))

    def test_basic_http(self):
        self.assertTrue(validate_url("http://example.com"))

    def test_with_path(self):
        self.assertTrue(validate_url("https://example.com/api/v1"))

    def test_no_scheme_rejected(self):
        self.assertFalse(validate_url("example.com"))

    def test_ftp_rejected(self):
        self.assertFalse(validate_url("ftp://example.com"))

    def test_whitespace_in_host_rejected(self):
        self.assertFalse(validate_url("https://exam ple.com"))

    def test_no_host_rejected(self):
        self.assertFalse(validate_url("https://"))


class TestCreateAccount(unittest.TestCase):
    def test_creates_with_valid_email(self):
        acct = create_account("u@example.com", "checking")
        self.assertEqual(acct["type"], "checking")

    def test_creates_with_valid_phone(self):
        acct = create_account("u@example.com", "checking", phone="1234567")
        self.assertEqual(acct["phone"], "1234567")

    def test_rejects_invalid_email(self):
        with self.assertRaises(ValueError):
            create_account("bad-email", "checking")

    def test_rejects_invalid_phone(self):
        with self.assertRaises(ValueError):
            create_account("u@example.com", "checking", phone="abc")


class TestUpdateAccountCallback(unittest.TestCase):
    def test_updates_with_valid_url(self):
        result = update_account_callback(1, "https://example.com/cb")
        self.assertEqual(result["callback_url"], "https://example.com/cb")

    def test_rejects_invalid_url(self):
        with self.assertRaises(ValueError):
            update_account_callback(1, "not-a-url")


if __name__ == "__main__":
    unittest.main()

